import React, { useEffect, useState } from "react";
import axios from "axios";

const API_BASE = process.env.REACT_APP_API_URL || "http://localhost:5000/api";
const SERVER_BASE = (process.env.REACT_APP_API_URL || "http://localhost:5000/api").replace(
	/\/api\/?$/,
	""
);

const buildFileUrl = (filePath) => {
	if (!filePath) {
		return "";
	}

	if (filePath.startsWith("http://") || filePath.startsWith("https://")) {
		return filePath;
	}

	const normalized = filePath.replace(/\\/g, "/").replace(/^\//, "");
	return `${SERVER_BASE}/${normalized}`;
};

function AdminComplaints() {
	const [complaints, setComplaints] = useState([]);
	const [loading, setLoading] = useState(true);
	const [error, setError] = useState("");
	const [updatingId, setUpdatingId] = useState("");
	const [deletingId, setDeletingId] = useState("");

	const getAuthHeaders = () => {
		const token = localStorage.getItem("token");
		return token ? { Authorization: `Bearer ${token}` } : {};
	};

	const fetchComplaints = async () => {
		setLoading(true);
		setError("");

		try {
			const token = localStorage.getItem("token");
			if (!token) {
				setError("Login required to view complaints.");
				setComplaints([]);
				return;
			}

			const { data } = await axios.get(`${API_BASE}/complaints`, {
				headers: getAuthHeaders()
			});

			const sorted = [...(Array.isArray(data) ? data : [])].sort(
				(a, b) => new Date(b.createdAt || 0) - new Date(a.createdAt || 0)
			);

			setComplaints(sorted);
		} catch (err) {
			setError(err?.response?.data?.message || "Failed to load complaints.");
			setComplaints([]);
		} finally {
			setLoading(false);
		}
	};

	const handleStatusChange = async (id, status) => {
		setUpdatingId(id);
		setError("");

		try {
			const { data } = await axios.put(
				`${API_BASE}/complaints/status/${id}`,
				{ status },
				{ headers: getAuthHeaders() }
			);

			setComplaints((prev) => prev.map((item) => (item._id === id ? { ...item, ...data } : item)));
		} catch (err) {
			setError(err?.response?.data?.message || "Failed to update status.");
		} finally {
			setUpdatingId("");
		}
	};

	const handleDelete = async (id) => {
		const ok = window.confirm("Are you sure you want to delete this complaint?");
		if (!ok) {
			return;
		}

		setDeletingId(id);
		setError("");

		try {
			await axios.delete(`${API_BASE}/complaints/${id}`, {
				headers: getAuthHeaders()
			});

			setComplaints((prev) => prev.filter((item) => item._id !== id));
		} catch (err) {
			setError(err?.response?.data?.message || "Failed to delete complaint.");
		} finally {
			setDeletingId("");
		}
	};

	useEffect(() => {
		fetchComplaints();
	}, []);

	return (
		<div className="container mt-4">
			<div className="d-flex justify-content-between align-items-center mb-3">
				<h3 className="mb-0">Admin Complaints</h3>
				<button className="btn btn-outline-primary" onClick={fetchComplaints}>
					Refresh
				</button>
			</div>

			{error && <div className="alert alert-danger">{error}</div>}

			{loading ? (
				<p className="text-muted">Loading complaints...</p>
			) : complaints.length === 0 ? (
				<div className="alert alert-info">No complaints found.</div>
			) : (
				<div className="table-responsive">
					<table className="table table-bordered table-hover align-middle">
						<thead className="table-light">
							<tr>
								<th>Title</th>
								<th>Description</th>
								<th>User</th>
								<th>Status</th>
								<th>File</th>
								<th>Actions</th>
							</tr>
						</thead>
						<tbody>
							{complaints.map((complaint) => {
								const isUpdating = updatingId === complaint._id;
								const isDeleting = deletingId === complaint._id;

								return (
									<tr key={complaint._id}>
										<td>{complaint.title || "-"}</td>
										<td style={{ maxWidth: 320 }}>
											<span className="d-inline-block text-truncate" style={{ maxWidth: "100%" }}>
												{complaint.description || "-"}
											</span>
										</td>
										<td>
											{complaint.userId?.name || "Unknown"}
											<br />
											<small className="text-muted">{complaint.userId?.email || "-"}</small>
										</td>
										<td>
											<select
												className="form-select form-select-sm"
												value={complaint.status || "Pending"}
												onChange={(e) => handleStatusChange(complaint._id, e.target.value)}
												disabled={isUpdating || isDeleting}
											>
												<option value="Pending">Pending</option>
												<option value="Resolved">Resolved</option>
											</select>
										</td>
										<td>
											{complaint.fileUrl ? (
												<a
													href={buildFileUrl(complaint.fileUrl)}
													target="_blank"
													rel="noreferrer"
													className="btn btn-sm btn-outline-secondary"
												>
													View File
												</a>
											) : (
												<span className="text-muted">No file</span>
											)}
										</td>
										<td>
											<button
												className="btn btn-sm btn-danger"
												onClick={() => handleDelete(complaint._id)}
												disabled={isDeleting || isUpdating}
											>
												{isDeleting ? "Deleting..." : "Delete"}
											</button>
										</td>
									</tr>
								);
							})}
						</tbody>
					</table>
				</div>
			)}
		</div>
	);
}

export default AdminComplaints;
